def gen(rng, size):
    m = max(2, size)
    n = max(2, size // 2)
    # ensure each column has at least one non-negative value
    mat = [[-1]*n for _ in range(m)]
    for c in range(n):
        r = rng.randint(0, m-1)
        mat[r][c] = rng.randint(0, 100)
    for r in range(m):
        for c in range(n):
            if mat[r][c] == -1 and rng.random() < 0.5:
                mat[r][c] = rng.randint(0, 100)
    return [mat]

