class Solution:
    def modifiedMatrix(self, matrix):
        m, n = len(matrix), len(matrix[0])
        result = [row[:] for row in matrix]
        for c in range(n):
            col_max = max(matrix[r][c] for r in range(m) if matrix[r][c] != -1)
            for r in range(m):
                if matrix[r][c] == -1:
                    result[r][c] = col_max
        return result

