class Solution:
    def modifiedMatrix(self, matrix):
        m, n = len(matrix), len(matrix[0])
        col_max = [max(matrix[r][c] for r in range(m) if matrix[r][c] != -1) for c in range(n)]
        return [[col_max[c] if matrix[r][c] == -1 else matrix[r][c] for c in range(n)] for r in range(m)]

