var modifiedMatrix = function(matrix) {
    const m = matrix.length, n = matrix[0].length;
    const colMax = Array(n).fill(-Infinity);
    for (let r = 0; r < m; r++)
        for (let c = 0; c < n; c++)
            if (matrix[r][c] !== -1 && matrix[r][c] > colMax[c]) colMax[c] = matrix[r][c];
    return matrix.map(row => row.map((v, c) => v === -1 ? colMax[c] : v));
};
